module top_module(clk, rst_n, out);input clk, rst_n;
    output [3:0] out;

    reg [3:0] cnt;

    always @(posedge clk, negedge rst_n) begin
        if(!rst_n) begin
            cnt <= 4'b0;
        end else begin
            if(cnt == 4'b1111) begin
                cnt <= 4'b0;
            end else begin
                cnt <= cnt + 1;
            end
        end
    end

    assign out = cnt;

endmodule
